import {
  forwardRef,
  useCallback,
  useEffect,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import ArvoIconButton from '../IconButton/IconButton';
import ArvoActionMenu from '../ActionMenu/ActionMenu';
import type { MenuItemData, MenuTrailingAction } from '../ActionMenu/ActionMenu';
import { useControllableState } from '../../hooks/useControllableState';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface TabItem {
  id: string;
  label: string;
  icon?: string;
  isDisabled?: boolean;
  pinned?: boolean;
  isClosable?: boolean;
  panelId?: string;
  order?: number;
}

export interface ArvoTabstripProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onSelect'> {
  variant?: 'primary' | 'secondary' | 'tertiary';
  size?: 'sm' | 'lg';
  tabs: TabItem[];
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  isClosable?: boolean;
  isPinnable?: boolean;
  actionsVisibility?: 'hover' | 'always';
  isDisabled?: boolean;
  isLoading?: boolean;
  onSelect?: (detail: { id: string; index: number }) => void;
  onClose?: (detail: { id: string; index: number }) => void;
  onPin?: (detail: { id: string; pinned: boolean; tabOrder: string[] }) => void;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function sortTabs(tabs: TabItem[]): TabItem[] {
  const pinned = tabs.filter((t) => t.pinned);
  const unpinned = tabs.filter((t) => !t.pinned);

  const byOrder = (a: TabItem, b: TabItem) => {
    const aO = a.order ?? Infinity;
    const bO = b.order ?? Infinity;
    if (aO !== Infinity || bO !== Infinity) return aO - bO;
    return 0;
  };

  pinned.sort(byOrder);
  unpinned.sort(byOrder);
  return [...pinned, ...unpinned];
}

function getTabOrder(tabs: TabItem[]): string[] {
  return sortTabs(tabs).map((t) => t.id);
}

function getActionsWidth(
  variant: string,
  size: string,
  isPinnable: boolean,
  isClosable: boolean,
  tab: TabItem,
  globalClosable: boolean,
): number {
  if (variant === 'tertiary') return 0;
  const btnSize = size === 'sm' ? 20 : 24;
  const gap = 1;
  let count = 0;
  if (isPinnable) count++;
  if (!tab.pinned && (tab.isClosable ?? globalClosable)) count++;
  if (count === 0) return 0;
  return count * btnSize + (count > 1 ? gap : 0) + 4;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const ArvoTabstrip = forwardRef<HTMLDivElement, ArvoTabstripProps>(
  function ArvoTabstrip(
    {
      variant = 'primary',
      size = 'lg',
      tabs,
      selectedId: selectedIdProp,
      defaultSelectedId,
      isClosable = false,
      isPinnable = false,
      actionsVisibility = 'hover',
      isDisabled = false,
      isLoading = false,
      onSelect,
      onClose,
      onPin,
      className,
      ...rest
    },
    ref,
  ) {
    const tabRefs = useRef<Map<string, HTMLDivElement>>(new Map());
    const listRef = useRef<HTMLDivElement>(null);
    const overflowBtnRef = useRef<HTMLDivElement>(null);

    const fallbackId = tabs.find((t) => !t.isDisabled)?.id ?? null;
    const [resolvedSelectedId, setSelectedId] = useControllableState(
      selectedIdProp,
      defaultSelectedId !== undefined ? defaultSelectedId : fallbackId,
    );

    const [hiddenTabIds, setHiddenTabIds] = useState<Set<string>>(new Set());
    const [promotedTabId, setPromotedTabId] = useState<string | null>(null);

    const iconBtnSize = size === 'sm' ? 'sm' : 'md';

    // ── Display order: pinned first, then unpinned ──────────────────────
    const displayOrder = useMemo(() => {
      const sorted = sortTabs(tabs);

      if (promotedTabId) {
        const idx = sorted.findIndex((t) => t.id === promotedTabId);
        if (idx >= 0 && !sorted[idx].pinned) {
          const [promoted] = sorted.splice(idx, 1);
          const firstUnpinnedIdx = sorted.findIndex((t) => !t.pinned);
          if (firstUnpinnedIdx >= 0) {
            sorted.splice(firstUnpinnedIdx, 0, promoted);
          } else {
            sorted.push(promoted);
          }
        }
      }

      return sorted;
    }, [tabs, promotedTabId]);

    const hasOverflow = hiddenTabIds.size > 0;

    const classes = [
      'arvo-tabs',
      `arvo-tabs--${variant}`,
      `arvo-tabs--${size}`,
      actionsVisibility === 'always' && 'arvo-tabs--actions-always',
      hasOverflow && 'has-overflow',
      isDisabled && 'is-disabled',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Overflow detection ────────────────────────────────────────────────
    useEffect(() => {
      const listEl = listRef.current;
      if (!listEl) return;

      let rafId: number;
      const checkOverflow = () => {
        cancelAnimationFrame(rafId);
        rafId = requestAnimationFrame(() => {
          const listRect = listEl.getBoundingClientRect();
          const tabEls = listEl.querySelectorAll<HTMLDivElement>('[role="tab"]');

          for (const tabEl of tabEls) {
            tabEl.style.visibility = '';
            tabEl.style.position = '';
            tabEl.style.pointerEvents = '';
          }

          const newHidden = new Set<string>();
          let firstOverflowReached = false;

          for (const tabEl of tabEls) {
            const tabRect = tabEl.getBoundingClientRect();
            if (firstOverflowReached || tabRect.right > listRect.right) {
              const id = tabEl.getAttribute('data-tab-id');
              if (id) newHidden.add(id);
              firstOverflowReached = true;
            }
          }

          if (newHidden.size > 0) {
            const testRect = listEl.getBoundingClientRect();
            const triggerW = 32;
            const adjustedWidth = testRect.width - triggerW;
            newHidden.clear();
            firstOverflowReached = false;

            for (const tabEl of tabEls) {
              const tabRect = tabEl.getBoundingClientRect();
              if (
                firstOverflowReached ||
                tabRect.right > testRect.left + adjustedWidth
              ) {
                const id = tabEl.getAttribute('data-tab-id');
                if (id) newHidden.add(id);
                firstOverflowReached = true;
              }
            }
          }

          if (promotedTabId && newHidden.has(promotedTabId)) {
            const lastVisibleUnpinned = displayOrder
              .filter((t) => !t.pinned && !newHidden.has(t.id))
              .pop();

            if (lastVisibleUnpinned) {
              newHidden.delete(promotedTabId);
              newHidden.add(lastVisibleUnpinned.id);
            }
          }

          for (const tabEl of tabEls) {
            const id = tabEl.getAttribute('data-tab-id');
            if (id && newHidden.has(id)) {
              tabEl.style.visibility = 'hidden';
              tabEl.style.position = 'absolute';
              tabEl.style.pointerEvents = 'none';
            }
          }

          setHiddenTabIds((prev) => {
            if (
              prev.size === newHidden.size &&
              [...prev].every((v) => newHidden.has(v))
            )
              return prev;
            return newHidden;
          });
        });
      };

      const observer = new ResizeObserver(checkOverflow);
      observer.observe(listEl);
      checkOverflow();

      return () => {
        observer.disconnect();
        cancelAnimationFrame(rafId);
      };
    }, [displayOrder, promotedTabId]);

    // ── Lock tab widths for hover mode ────────────────────────────────────
    useLayoutEffect(() => {
      if (actionsVisibility !== 'hover') return;
      tabRefs.current.forEach((el) => {
        el.style.minWidth = '';
      });
      requestAnimationFrame(() => {
        tabRefs.current.forEach((el) => {
          el.style.minWidth = `${el.offsetWidth}px`;
        });
      });
    }, [actionsVisibility, displayOrder, size]);

    // ── Keyboard navigation ─────────────────────────────────────────────
    const getEnabledTabs = useCallback(
      (): TabItem[] =>
        displayOrder.filter((t) => !t.isDisabled && !hiddenTabIds.has(t.id)),
      [displayOrder, hiddenTabIds],
    );

    const focusTab = useCallback((tabId: string) => {
      tabRefs.current.get(tabId)?.focus();
    }, []);

    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        if (isDisabled || isLoading) return;
        const enabled = getEnabledTabs();
        if (enabled.length === 0) return;

        const currentIdx = enabled.findIndex(
          (t) => t.id === document.activeElement?.getAttribute('data-tab-id'),
        );
        if (currentIdx < 0) return;

        let nextIdx: number | null = null;

        switch (e.key) {
          case 'ArrowRight':
            e.preventDefault();
            nextIdx = (currentIdx + 1) % enabled.length;
            break;
          case 'ArrowLeft':
            e.preventDefault();
            nextIdx =
              (currentIdx - 1 + enabled.length) % enabled.length;
            break;
          case 'Home':
            e.preventDefault();
            nextIdx = 0;
            break;
          case 'End':
            e.preventDefault();
            nextIdx = enabled.length - 1;
            break;
          case 'Enter':
          case ' ':
            e.preventDefault();
            if (enabled[currentIdx].id !== resolvedSelectedId) {
              const tabsIdx = tabs.findIndex(
                (t) => t.id === enabled[currentIdx].id,
              );
              setSelectedId(enabled[currentIdx].id);
              setPromotedTabId(null);
              onSelect?.({ id: enabled[currentIdx].id, index: tabsIdx });
            }
            return;
          case 'Delete': {
            const tab = enabled[currentIdx];
            if (tab.pinned) return;
            const tabClosable = tab.isClosable ?? isClosable;
            if (tabClosable) {
              e.preventDefault();
              const tabsIdx = tabs.findIndex((t) => t.id === tab.id);
              onClose?.({ id: tab.id, index: tabsIdx });
            }
            return;
          }
          default:
            return;
        }

        if (nextIdx !== null) {
          focusTab(enabled[nextIdx].id);
        }
      },
      [isDisabled, isLoading, getEnabledTabs, resolvedSelectedId, tabs, isClosable, onSelect, onClose, focusTab, setSelectedId],
    );

    // ── Focus management: keep tabindex in sync ─────────────────────────
    useEffect(() => {
      if (resolvedSelectedId) {
        tabRefs.current.get(resolvedSelectedId)?.setAttribute('tabindex', '0');
      }
    }, [resolvedSelectedId]);

    // ── Clear promoted tab when selection changes from the strip ──────────
    const handleTabClick = useCallback(
      (tab: TabItem, index: number) => {
        if (tab.isDisabled || isDisabled || isLoading) return;
        if (tab.id !== resolvedSelectedId) {
          setSelectedId(tab.id);
          setPromotedTabId(null);
          onSelect?.({ id: tab.id, index });
        }
      },
      [isDisabled, isLoading, resolvedSelectedId, setSelectedId, onSelect],
    );

    // ── Overflow menu: build items ──────────────────────────────────────
    const overflowMenuItems: MenuItemData[] = useMemo(() => {
      const showActions = variant !== 'tertiary';
      return displayOrder
        .filter((t) => hiddenTabIds.has(t.id))
        .map((tab) => {
          const trailingActions: MenuTrailingAction[] = [];

          if (showActions && isPinnable) {
            trailingActions.push({
              id: `pin-${tab.id}`,
              icon: tab.pinned ? 'push-pin-filled' : 'push-pin',
              ariaLabel: tab.pinned ? 'Unpin tab' : 'Pin tab',
              isDisabled: tab.isDisabled || isDisabled,
              onClick: () => {
                const newPinned = !tab.pinned;
                const updated = tabs.map((t) =>
                  t.id === tab.id ? { ...t, pinned: newPinned } : t,
                );
                onPin?.({
                  id: tab.id,
                  pinned: newPinned,
                  tabOrder: getTabOrder(updated),
                });
                return false;
              },
            });
          }

          if (showActions && !tab.pinned && (tab.isClosable ?? isClosable)) {
            trailingActions.push({
              id: `close-${tab.id}`,
              icon: 'close',
              ariaLabel: 'Close tab',
              isDisabled: tab.isDisabled || isDisabled,
              onClick: () => {
                const idx = tabs.findIndex((t) => t.id === tab.id);
                onClose?.({ id: tab.id, index: idx });
                return false;
              },
            });
          }

          return {
            id: tab.id,
            label: tab.label,
            icon: tab.icon,
            isDisabled: tab.isDisabled,
            active: tab.id === resolvedSelectedId,
            trailingActions: trailingActions.length > 0 ? trailingActions : undefined,
          } satisfies MenuItemData;
        });
    }, [displayOrder, hiddenTabIds, variant, isPinnable, isClosable, isDisabled, tabs, resolvedSelectedId, onPin, onClose]);

    const handleOverflowSelect = useCallback(
      (item: MenuItemData) => {
        if (item.isDisabled) return;
        const idx = tabs.findIndex((t) => t.id === item.id);
        setSelectedId(item.id);
        setPromotedTabId(item.id);
        onSelect?.({ id: item.id, index: idx });
      },
      [tabs, setSelectedId, onSelect],
    );

    // ── Render tabs ─────────────────────────────────────────────────────
    const showActions = variant !== 'tertiary';

    const tabElements = displayOrder.map((tab) => {
      const index = tabs.findIndex((t) => t.id === tab.id);
      const isSelected = tab.id === resolvedSelectedId;
      const isTabDisabled = tab.isDisabled || isDisabled;
      const tabClosable = showActions && !tab.pinned && (tab.isClosable ?? isClosable);
      const tabPinnable = showActions && isPinnable;

      const tabClasses = [
        'arvo-tabs__tab',
        isSelected && 'active',
        isTabDisabled && 'is-disabled',
        tab.pinned && 'is-pinned',
      ]
        .filter(Boolean)
        .join(' ');

      const handleClick = () => handleTabClick(tab, index);

      const handlePinClick = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (isDisabled || isLoading) return;
        const newPinned = !tab.pinned;
        const updated = tabs.map((t) =>
          t.id === tab.id ? { ...t, pinned: newPinned } : t,
        );
        onPin?.({
          id: tab.id,
          pinned: newPinned,
          tabOrder: getTabOrder(updated),
        });
      };

      const handleCloseClick = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (isDisabled || isLoading) return;
        onClose?.({ id: tab.id, index });
      };

      const actionsW = getActionsWidth(
        variant,
        size,
        isPinnable,
        isClosable,
        tab,
        isClosable,
      );

      const tabStyle: React.CSSProperties | undefined =
        actionsVisibility === 'hover' && actionsW > 0
          ? ({ '--arvo-tabs-actions-w': `${actionsW}px` } as React.CSSProperties)
          : undefined;

      return (
        <div
          key={tab.id}
          ref={(el) => {
            if (el) tabRefs.current.set(tab.id, el);
            else tabRefs.current.delete(tab.id);
          }}
          role="tab"
          className={tabClasses}
          data-tab-id={tab.id}
          aria-selected={isSelected}
          aria-controls={tab.panelId || undefined}
          aria-disabled={isTabDisabled || undefined}
          tabIndex={isSelected ? 0 : -1}
          style={tabStyle}
          onClick={handleClick}
          onKeyDown={handleKeyDown}
        >
          <span className="arvo-tabs__tab-lft">
            {tab.icon && (
              <span
                className={`arvo-tabs__tab-ico o9con o9con-${tab.icon}`}
                aria-hidden="true"
              />
            )}
            <span className="arvo-tabs__tab-lbl">{tab.label}</span>
          </span>
          {showActions && (tabPinnable || tabClosable) && (
            <span className="arvo-tabs__tab-actions">
              {tabPinnable && (
                <ArvoIconButton
                  icon={tab.pinned ? 'push-pin-filled' : 'push-pin'}
                  variant="tertiary"
                  size={iconBtnSize}
                  tooltip={tab.pinned ? 'Unpin tab' : 'Pin tab'}
                  isDisabled={isDisabled}
                  isLoading={isLoading}
                  isSelected={tab.pinned}
                  onClick={handlePinClick}
                  tabIndex={-1}
                />
              )}
              {tabClosable && (
                <ArvoIconButton
                  icon="close"
                  variant="tertiary"
                  size={iconBtnSize}
                  tooltip="Close tab"
                  isDisabled={isDisabled}
                  isLoading={isLoading}
                  onClick={handleCloseClick}
                  tabIndex={-1}
                />
              )}
            </span>
          )}
        </div>
      );
    });

    const overflowTrigger = (
      <ArvoIconButton
        icon="ellipsis-v"
        variant="tertiary"
        size={iconBtnSize}
        tooltip="More tabs"
        isDisabled={isDisabled}
        isLoading={isLoading}
        tabIndex={-1}
      />
    );

    return (
      <div
        ref={ref}
        className={classes}
        aria-busy={isLoading || undefined}
        {...rest}
      >
        <div
          ref={listRef}
          className="arvo-tabs__list"
          role="tablist"
          aria-orientation="horizontal"
          aria-label={rest['aria-label'] || 'Tabs'}
        >
          {tabElements}
        </div>
        <div ref={overflowBtnRef} className="arvo-tabs__overflow-btn">
          {hasOverflow ? (
            <ArvoActionMenu
              items={overflowMenuItems}
              trigger={overflowTrigger}
              placement="bottom-end"
              trailingActionsVisibility={actionsVisibility === 'always' ? 'always' : 'hover'}
              closeOnSelect
              isDisabled={isDisabled}
              onSelect={handleOverflowSelect}
            />
          ) : (
            <ArvoIconButton
              icon="ellipsis-v"
              variant="tertiary"
              size={iconBtnSize}
              tooltip="More tabs"
              isDisabled={isDisabled}
              isLoading={isLoading}
              tabIndex={-1}
              style={{ display: 'none' }}
            />
          )}
        </div>
      </div>
    );
  },
);

export default ArvoTabstrip;
